import React, { useState, useEffect } from "react";
import axios from "axios";
import "../styles/Contact.css";

const Contact = () => {
  // Form states
  const [contactForm, setContactForm] = useState({
    subject: "",
    message: "",
  });

  const [authForm, setAuthForm] = useState({
    username: "",
    email: "",
    password: "",
    confirmPassword: "",
    isAdmin: false
  });

  // UI states
  const [isSubmitting, setIsSubmitting] = useState(false);
  const [submitStatus, setSubmitStatus] = useState(null);
  const [error, setError] = useState(null);
  const [isLoggedIn, setIsLoggedIn] = useState(false);
  const [showSignUp, setShowSignUp] = useState(false);
  const [userInfo, setUserInfo] = useState(null);
  const [messages, setMessages] = useState([]);

  useEffect(() => {
    const token = localStorage.getItem("token");
    const user = localStorage.getItem("user");
    
    if (token && user) {
      try {
        // Verify the token and user data are valid
        const parsedUser = JSON.parse(user);
        if (parsedUser && parsedUser.email) {
          setIsLoggedIn(true);
          setUserInfo(parsedUser);
          fetchUserMessages(token);
        } else {
          // Invalid user data - force logout
          handleLogout();
        }
      } catch (e) {
        console.error("Error parsing user data:", e);
        handleLogout();
      }
    }
  }, []);

  const fetchUserMessages = async (token) => {
    try {
      // Add console log to verify token
      console.log("Fetching messages with token:", token);
      
      const response = await axios.get("https://localhost:7235/api/messages/user", {
        headers: { 
          'Authorization': `Bearer ${token}`,
          'Content-Type': 'application/json'
        }
      });
      
      // Add response logging
      console.log("Messages response:", response.data);
      
      if (response.data && Array.isArray(response.data)) {
        setMessages(response.data);
      } else {
        setError("Received unexpected messages format");
        setMessages([]);
      }
    } catch (err) {
      // Enhanced error logging
      console.error("Error fetching messages:", {
        error: err,
        response: err.response,
        message: err.message
      });
      
      setError("Failed to load messages. Please try again later.");
      setMessages([]); // Ensure messages array is cleared on error
    }
  };

  // Handle form input changes
  const handleContactChange = (e) => {
    const { name, value } = e.target;
    setContactForm(prev => ({ ...prev, [name]: value }));
  };

  const handleAuthChange = (e) => {
    const { name, value, type, checked } = e.target;
    setAuthForm(prev => ({
      ...prev,
      [name]: type === "checkbox" ? checked : value
    }));
  };

  // Form validation
  const validateContactForm = () => {
    const { subject, message } = contactForm;
    
    if (!subject.trim()) {
      setError("Subject is required");
      return false;
    }
    if (subject.length > 100) {
      setError("Subject must be less than 100 characters");
      return false;
    }
    if (!message.trim()) {
      setError("Message is required");
      return false;
    }
    if (message.length > 5000) {
      setError("Message must be less than 5000 characters");
      return false;
    }
    
    setError(null);
    return true;
  };

  const validateAuthForm = (isLogin) => {
    const { email, password, confirmPassword, username } = authForm;
    
    if (isLogin) {
      if (!email) {
        setError("Email is required");
        return false;
      }
      if (!password) {
        setError("Password is required");
        return false;
      }
    } else {
      if (!username.trim()) {
        setError("Username is required");
        return false;
      }
      if (!email) {
        setError("Email is required");
        return false;
      }
      if (!/^\S+@\S+\.\S+$/.test(email)) {
        setError("Please enter a valid email");
        return false;
      }
      if (!password) {
        setError("Password is required");
        return false;
      }
      if (password.length < 6) {
        setError("Password must be at least 6 characters");
        return false;
      }
      if (password !== confirmPassword) {
        setError("Passwords don't match");
        return false;
      }
    }
    
    setError(null);
    return true;
  };

  // Authentication handlers
  const handleLogin = async (e) => {
    e.preventDefault();
    if (!validateAuthForm(true)) return;

    setIsSubmitting(true);
    try {
      const response = await axios.post("https://localhost:7235/api/auth/signin", {
        email: authForm.email,
        password: authForm.password
      });

      const { token, user } = response.data;
      
      localStorage.setItem("token", token);
      localStorage.setItem("user", JSON.stringify(user));
      
      setIsLoggedIn(true);
      setUserInfo(user);
      setSubmitStatus({
        type: "auth-success",
        message: "Login successful!"
      });
      setError(null);
      
      setAuthForm({
        username: "",
        email: "",
        password: "",
        confirmPassword: "",
        isAdmin: false
      });
      
      await fetchUserMessages(token);
    } catch (err) {
      const errorMsg = err.response?.data?.message || "Invalid credentials";
      setError(errorMsg);
      setSubmitStatus({
        type: "auth-error",
        message: "Login failed"
      });
    } finally {
      setIsSubmitting(false);
    }
  };

  const handleSignup = async (e) => {
    e.preventDefault();
    if (!validateAuthForm(false)) return;

    setIsSubmitting(true);
    try {
      const response = await axios.post("https://localhost:7235/api/auth/signup", {
        username: authForm.username,
        email: authForm.email,
        password: authForm.password,
        confirmPassword: authForm.confirmPassword,
        isAdmin: authForm.isAdmin
      });

      setSubmitStatus({
        type: "auth-success",
        message: "Registration successful! Please sign in."
      });
      setError(null);
      setShowSignUp(false);
      
      setAuthForm({
        username: "",
        email: "",
        password: "",
        confirmPassword: "",
        isAdmin: false
      });
    } catch (err) {
      const errorMsg = err.response?.data?.message || 
                     err.response?.data?.errors?.[0] || 
                     "Registration failed";
      setError(errorMsg);
      setSubmitStatus({
        type: "auth-error",
        message: "Registration failed"
      });
    } finally {
      setIsSubmitting(false);
    }
  };

  // Message submission handler
  const handleSubmitMessage = async (e) => {
    e.preventDefault();
    if (!validateContactForm()) return;

    setIsSubmitting(true);
    setSubmitStatus(null);
    setError(null);
    
    try {
      const token = localStorage.getItem("token");
      const response = await axios.post("https://localhost:7235/api/messages", {
        subject: contactForm.subject,
        content: contactForm.message
      }, {
        headers: { 'Authorization': `Bearer ${token}` }
      });

      // On success:
      setSubmitStatus({
        type: "message-success",
        message: "✅ Message sent successfully!",
        sentMessage: {
          subject: contactForm.subject,
          content: contactForm.message,
          sentAt: new Date().toISOString(),
          id: response.data.messageId || Date.now() // Fallback ID if not returned
        }
      });

      // Reset form
      setContactForm({
        subject: "",
        message: "",
      });

      // Add the new message to the top of the messages list
      setMessages(prev => [{
        id: response.data.messageId || Date.now(),
        subject: contactForm.subject,
        content: contactForm.message,
        sentAt: new Date().toISOString()
      }, ...prev]);

    } catch (err) {
      const errorMsg = err.response?.data?.message || 
                     err.response?.data?.errors?.[0] || 
                     "Failed to send message. Please try again.";
      setError(errorMsg);
      setSubmitStatus({
        type: "message-error",
        message: "❌ Failed to send message"
      });
    } finally {
      setIsSubmitting(false);
    }
  };

  // Logout handler
  const handleLogout = () => {
    localStorage.removeItem("token");
    localStorage.removeItem("user");
    setIsLoggedIn(false);
    setUserInfo(null);
    setMessages([]);
    setSubmitStatus(null);
    setError(null);
  };

  // Render methods for different form states
  const renderLoggedInContent = () => (
    <>
      <div className="user-header">
        <h3>Welcome, {userInfo?.username || "User"}!</h3>
        {userInfo?.isAdmin && <span className="admin-badge">Admin</span>}
        <button onClick={handleLogout} className="logout-btn">Logout</button>
      </div>
      
      <h4>LEAVE US A MESSAGE</h4>
      
      {error && <div className="error-message">❌ {error}</div>}
      {submitStatus?.type === "message-success" && (
        <div className="success-message">{submitStatus.message}</div>
      )}
      {submitStatus?.type === "message-error" && (
        <div className="error-message">{submitStatus.message}</div>
      )}

      <form onSubmit={handleSubmitMessage}>
        <input
          type="text"
          name="subject"
          placeholder="Subject"
          value={contactForm.subject}
          onChange={handleContactChange}
          required
          maxLength="100"
        />
        <textarea
          name="message"
          placeholder="Write your message here..."
          value={contactForm.message}
          onChange={handleContactChange}
          required
          maxLength="5000"
        ></textarea>

        <button 
          type="submit" 
          disabled={isSubmitting}
          className={isSubmitting ? "submitting" : ""}
        >
          {isSubmitting ? (
            <>
              <span className="spinner"></span>
              Sending...
            </>
          ) : (
            "Submit Message"
          )}
        </button>
      </form>

      <div className="message-history-container">
        <h4>YOUR MESSAGES</h4>
        
        {messages.length === 0 && !submitStatus?.sentMessage ? (
          <div className="no-messages">
            <p>You haven't sent any messages yet.</p>
          </div>
        ) : (
          <ul className="messages-list">
            {submitStatus?.type === "message-success" && submitStatus?.sentMessage && (
              <li key={submitStatus.sentMessage.id} className="highlight-new-message">
                <div className="message-subject">{submitStatus.sentMessage.subject}</div>
                <div className="message-content">{submitStatus.sentMessage.content}</div>
                <div className="message-date">
                  {new Date(submitStatus.sentMessage.sentAt).toLocaleString()} (Just now)
                </div>
              </li>
            )}
            
            {messages.map(msg => (
              <li key={msg.id}>
                <div className="message-subject">{msg.subject}</div>
                <div className="message-content">{msg.content}</div>
                <div className="message-date">
                  {new Date(msg.sentAt).toLocaleString()}
                </div>
              </li>
            ))}
          </ul>
        )}
      </div>
    </>
  );

  const renderSignUpForm = () => (
    <>
      <h3>SIGN UP</h3>
      
      {error && <div className="error-message">❌ {error}</div>}
      {submitStatus?.type === "auth-success" && (
        <div className="success-message">{submitStatus.message}</div>
      )}

      <form onSubmit={handleSignup}>
        <input
          type="text"
          name="username"
          placeholder="Username"
          value={authForm.username}
          onChange={handleAuthChange}
          required
          maxLength="100"
        />
        <input
          type="email"
          name="email"
          placeholder="Email"
          value={authForm.email}
          onChange={handleAuthChange}
          required
        />
        <input
          type="password"
          name="password"
          placeholder="Password (min 6 characters)"
          value={authForm.password}
          onChange={handleAuthChange}
          required
          minLength="6"
        />
        <input
          type="password"
          name="confirmPassword"
          placeholder="Confirm Password"
          value={authForm.confirmPassword}
          onChange={handleAuthChange}
          required
        />
        
        <div className="form-group">
          <label>
            <input
              type="checkbox"
              name="isAdmin"
              checked={authForm.isAdmin}
              onChange={handleAuthChange}
            />
            Register as Admin
          </label>
        </div>

        <button 
          type="submit" 
          disabled={isSubmitting}
          className={isSubmitting ? "submitting" : ""}
        >
          {isSubmitting ? (
            <>
              <span className="spinner"></span>
              Signing Up...
            </>
          ) : (
            "Sign Up"
          )}
        </button>
      </form>
      
      <p className="auth-switch">
        Already have an account? 
        <button onClick={() => setShowSignUp(false)}>Sign In</button>
      </p>
    </>
  );

  const renderSignInForm = () => (
    <>
      <h3>SIGN IN</h3>
      
      {error && <div className="error-message">❌ {error}</div>}
      {submitStatus?.type === "auth-success" && (
        <div className="success-message">{submitStatus.message}</div>
      )}

      <form onSubmit={handleLogin}>
        <input
          type="email"
          name="email"
          placeholder="Email"
          value={authForm.email}
          onChange={handleAuthChange}
          required
        />
        <input
          type="password"
          name="password"
          placeholder="Password"
          value={authForm.password}
          onChange={handleAuthChange}
          required
        />

        <button 
          type="submit" 
          disabled={isSubmitting}
          className={isSubmitting ? "submitting" : ""}
        >
          {isSubmitting ? (
            <>
              <span className="spinner"></span>
              Signing In...
            </>
          ) : (
            "Sign In"
          )}
        </button>
      </form>
      
      <p className="auth-switch">
        Don't have an account? 
        <button onClick={() => setShowSignUp(true)}>Sign Up</button>
      </p>
    </>
  );

  return (
    <div id="contact" className="contact-container">
      <h1>CONTACT US</h1>

      <div className="map-container">
        <iframe
          title="Google Map"
          className="google-map"
          src="https://www.google.com/maps/embed?pb=!1m18!1m12!1m3!1d3048.146201882546!2d44.62674911141569!3d40.18355967135914!2m3!1f0!2f0!3f0!3m2!1i1024!2i768!4f13.1!3m3!1m2!1s0x406aa5fb2d2aeb97%3A0x7a90e13129b8e750!2z1Y7VuNaC1aTVvSDUv9Wl1bbVv9aA1bjVtg!5e0!3m2!1shy!2sam!4v1743157411782!5m2!1shy!2sam"
          allowFullScreen
          loading="lazy"
          referrerPolicy="no-referrer-when-downgrade"
        ></iframe>
      </div>

      <div className="contact-content">
        <div className="contact-info">
          <h2>Law Office</h2>
          <div className="info-item">
            <span className="icon">📍</span>
            <div>
              <h3>Address</h3>
              <p>Armenia, Yerevan City</p>
              <p>Woods Centre</p>
            </div>
          </div>
          <div className="info-item">
            <span className="icon">📞</span>
            <div>
              <h3>Phone</h3>
              <p>+374 12 34 56 78</p>
            </div>
          </div>
          <div className="info-item">
            <span className="icon">📧</span>
            <div>
              <h3>E-mail</h3>
              <p>info@law.com</p>
            </div>
          </div>
        </div>

        <div className="contact-form">
          {isLoggedIn ? renderLoggedInContent() : 
           showSignUp ? renderSignUpForm() : renderSignInForm()}
        </div>
      </div>
    </div>
  );
};

export default Contact;
